'use strict';

/**
 * Build step: compile everything under public/ into a single generated JS
 * module (server/webAssets.generated.js) that maps URL path -> { type, base64 }.
 *
 * pkg reliably bundles required JS modules but not globbed static assets, so
 * this makes the packaged exe fully self-contained. In development the server
 * still reads the real files from disk; the bundle is only used as a fallback
 * (i.e. inside the packaged executable).
 */

const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '..');
const PUBLIC_DIR = path.join(ROOT, 'public');
const OUT = path.join(ROOT, 'server', 'webAssets.generated.js');

const MIME = {
  '.html': 'text/html; charset=utf-8',
  '.js': 'text/javascript; charset=utf-8',
  '.mjs': 'text/javascript; charset=utf-8',
  '.css': 'text/css; charset=utf-8',
  '.json': 'application/json; charset=utf-8',
  '.svg': 'image/svg+xml',
  '.ico': 'image/x-icon',
  '.png': 'image/png',
  '.jpg': 'image/jpeg',
  '.jpeg': 'image/jpeg',
  '.gif': 'image/gif',
  '.webp': 'image/webp',
  '.woff': 'font/woff',
  '.woff2': 'font/woff2',
};

function walk(dir, out = []) {
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) walk(full, out);
    else out.push(full);
  }
  return out;
}

function build() {
  if (!fs.existsSync(PUBLIC_DIR)) {
    throw new Error(`public/ not found at ${PUBLIC_DIR}`);
  }
  const files = walk(PUBLIC_DIR);
  const map = {};
  for (const file of files) {
    const rel = '/' + path.relative(PUBLIC_DIR, file).split(path.sep).join('/');
    const ext = path.extname(file).toLowerCase();
    map[rel] = {
      type: MIME[ext] || 'application/octet-stream',
      base64: fs.readFileSync(file).toString('base64'),
    };
  }

  const header =
    '// AUTO-GENERATED by scripts/bundle-public.js — do not edit by hand.\n' +
    "'use strict';\n";
  const body = `module.exports = ${JSON.stringify(map)};\n`;
  fs.writeFileSync(OUT, header + body);
  // eslint-disable-next-line no-console
  console.log(`Bundled ${files.length} files (${(Buffer.byteLength(body) / 1024).toFixed(0)} KB) -> ${path.relative(ROOT, OUT)}`);
}

build();
